class RedisSessionManager:
    """Manages user sessions stored in Redis."""

    def __init__(self, redis_conn, prefix=SESSION_PREFIX, expiry=SESSION_EXPIRY):
        self.redis = redis_conn
        self.prefix = prefix
        self.expiry = expiry

    def create_session(self, user_data):
        """Create a new session and return the session ID."""
        session_id = str(uuid.uuid4())
        key = f"{self.prefix}{session_id}"
        session_data = {
            "user_data": json.dumps(user_data),
            "created_at": datetime.utcnow().isoformat(),
            "last_accessed": datetime.utcnow().isoformat(),
        }
        # Use SET with hash map for structured session data
        self.redis.hset(key, mapping=session_data)
        self.redis.expire(key, self.expiry)
        return session_id

    def get_session(self, session_id):
        """Retrieve session data by session ID."""
        key = f"{self.prefix}{session_id}"
        session_data = self.redis.hgetall(key)
        if not session_data:
            return None
        # Update last accessed time and refresh TTL
        self.redis.hset(key, "last_accessed", datetime.utcnow().isoformat())
        self.redis.expire(key, self.expiry)
        # Parse user_data from JSON
        if "user_data" in session_data:
            session_data["user_data"] = json.loads(session_data["user_data"])
        return session_data

    def update_session(self, session_id, user_data):
        """Update session data."""
        key = f"{self.prefix}{session_id}"
        if not self.redis.exists(key):
            return False
        self.redis.hset(key, "user_data", json.dumps(user_data))
        self.redis.hset(key, "last_accessed", datetime.utcnow().isoformat())
        self.redis.expire(key, self.expiry)
        return True

    def delete_session(self, session_id):
        """Delete a session."""
        key = f"{self.prefix}{session_id}"
        return self.redis.delete(key) > 0

    def set_session_value(self, session_id, field, value):
        """Set a specific field in the session using SET-like semantics."""
        key = f"{self.prefix}{session_id}"
        if not self.redis.exists(key):
            return False
        self.redis.hset(key, field, json.dumps(value) if not isinstance(value, str) else value)
        self.redis.expire(key, self.expiry)
        return True

    def get_session_value(self, session_id, field):
        """Get a specific field from the session using GET-like semantics."""
        key = f"{self.prefix}{session_id}"
        value = self.redis.hget(key, field)
        if value is None:
            return None
        try:
            return json.loads(value)
        except (json.JSONDecodeError, TypeError):
            return value


