class SimpleRedisSessionStore:
    """Simple session store using Redis SET and GET commands directly."""

    def __init__(self, redis_conn, prefix=SESSION_PREFIX, expiry=SESSION_EXPIRY):
        self.redis = redis_conn
        self.prefix = prefix
        self.expiry = expiry

    def set(self, session_id, data):
        """Store session data using Redis SET command."""
        key = f"{self.prefix}{session_id}"
        self.redis.set(key, json.dumps(data), ex=self.expiry)
        return True

    def get(self, session_id):
        """Retrieve session data using Redis GET command."""
        key = f"{self.prefix}{session_id}"
        data = self.redis.get(key)
        if data is None:
            return None
        # Refresh TTL on access
        self.redis.expire(key, self.expiry)
        return json.loads(data)

    def delete(self, session_id):
        """Delete session data."""
        key = f"{self.prefix}{session_id}"
        return self.redis.delete(key) > 0

