def redis_cache(ttl=DEFAULT_CACHE_TTL, prefix=CACHE_PREFIX, key_builder=None):
    """
    Caching decorator for expensive database queries and function calls.
    
    Args:
        ttl: Time-to-live in seconds for cached results.
        prefix: Redis key prefix for cache entries.
        key_builder: Optional custom function to build cache keys.
    
    Usage:
        @redis_cache(ttl=600)
        def get_user_profile(user_id):
            # expensive database query
            return db.query(...)
    """
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            # Build cache key
            if key_builder:
                cache_key = f"{prefix}{key_builder(*args, **kwargs)}"
            else:
                # Generate key from function name and arguments
                key_parts = [func.__module__, func.__qualname__]
                if args:
                    key_parts.append(str(args))
                if kwargs:
                    key_parts.append(str(sorted(kwargs.items())))
                raw_key = ":".join(key_parts)
                hashed_key = hashlib.md5(raw_key.encode()).hexdigest()
                cache_key = f"{prefix}{func.__qualname__}:{hashed_key}"

            # Try to get from cache
            try:
                cached_result = redis_pooled_client.get(cache_key)
                if cached_result is not None:
                    return json.loads(cached_result)
            except (redis.RedisError, json.JSONDecodeError):
                # If Redis is down or data is corrupted, fall through to function
                pass

            # Execute the function
            result = func(*args, **kwargs)

            # Store in cache
            try:
                redis_pooled_client.set(
                    cache_key,
                    json.dumps(result),
                    ex=ttl,
                )
            except redis.RedisError:
                # If Redis is down, just return the result without caching
                pass

            return result

        # Add cache invalidation helper
        def invalidate(*args, **kwargs):
            """Invalidate the cache for specific arguments."""
            if key_builder:
                cache_key = f"{prefix}{key_builder(*args, **kwargs)}"
            else:
                key_parts = [func.__module__, func.__qualname__]
                if args:
                    key_parts.append(str(args))
                if kwargs:
                    key_parts.append(str(sorted(kwargs.items())))
                raw_key = ":".join(key_parts)
                hashed_key = hashlib.md5(raw_key.encode()).hexdigest()
                cache_key = f"{prefix}{func.__qualname__}:{hashed_key}"
            try:
                redis_pooled_client.delete(cache_key)
            except redis.RedisError:
                pass

        def invalidate_all():
            """Invalidate all cache entries for this function."""
            pattern = f"{prefix}{func.__qualname__}:*"
            try:
                cursor = 0
                while True:
                    cursor, keys = redis_pooled_client.scan(cursor, match=pattern, count=100)
                    if keys:
                        redis_pooled_client.delete(*keys)
                    if cursor == 0:
                        break
            except redis.RedisError:
                pass

        wrapper.invalidate = invalidate
        wrapper.invalidate_all = invalidate_all
        return wrapper
    return decorator


