@app.after_request
def add_session_header(response):
    """Add session ID to response headers."""
    if hasattr(g, "session_id") and g.session_id:
        response.headers["X-Session-ID"] = g.session_id
    return response


def require_session(f):
    """Decorator to require a valid session for an endpoint."""
    @functools.wraps(f)
    def decorated(*args, **kwargs):
        if not g.session_data:
            return jsonify({"error": "Unauthorized. Valid session required."}), 401
        return f(*args, **kwargs)
    return decorated


